  typeof process !== 'undefined' && process.env?.PUBLIC_ASSOCIATE_TAG
    ? process.env.PUBLIC_ASSOCIATE_TAG
    : SPAWN_TAG !== '__ASSOCIATE_TAG__'
      ? SPAWN_TAG
      : 'inkledger-20';

