export function allCuratedAsins() {
  const set = new Set();
  for (const pick of HOMEPAGE_COMPARE_PICKS) set.add(pick.asin.toUpperCase());
  for (const pick of BOTTOM_STRIP_PICKS) set.add(pick.asin.toUpperCase());
  return set;
}

export function amazonRegistryHref(asin, tag = ASSOCIATE_TAG) {
  const id = String(asin || '').trim().toUpperCase();
  if (!id) return '#';
  return `https://www.amazon.com/dp/${id}?tag=${tag}&linkCode=ll1&language=en_US`;
}

export function bottomStripPickImage(asin) {
  return amazonInlineImageUrl(asin);
}
